mapper.select:
SELECT mr.id, mr.org_id, mr.clinic_id, c.clinic_name, mr.record_no, mr.patient_id, p.patient_name, mr.appointment_id, a.appointment_no, mr.doctor_id, d.staff_name AS doctor_name, mr.visit_type, mr.visit_date, mr.record_status, mr.signed_flag, mr.signed_at, mr.chief_complaint, mr.preliminary_diagnosis, mr.remark FROM medical_record mr LEFT JOIN clinic c ON c.id = mr.clinic_id LEFT JOIN patient p ON p.id = mr.patient_id LEFT JOIN appointment a ON a.id = mr.appointment_id LEFT JOIN staff d ON d.id = mr.doctor_id WHERE mr.is_deleted = 0 AND mr.org_id = #{orgId}
AND mr.clinic_id IN
#{clinicId}
AND mr.doctor_id = #{staffId}
AND mr.patient_id = #{query.patientId}
AND mr.doctor_id = #{query.doctorId}
AND mr.clinic_id = #{query.clinicId}
AND mr.record_status = #{query.recordStatus}
AND mr.visit_date >= #{query.visitDateFrom}
AND mr.visit_date < DATE_ADD(#{query.visitDateTo}, INTERVAL 1 DAY)
AND ( mr.record_no LIKE CONCAT('%', #{query.keyword}, '%') OR p.patient_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.mobile LIKE CONCAT('%', #{query.keyword}, '%') OR d.staff_name LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY mr.visit_date DESC, mr.id DESC

SELECT mr.id, mr.org_id, mr.clinic_id, c.clinic_name, mr.record_no, mr.patient_id, p.patient_name, p.mobile AS patient_mobile, mr.appointment_id, a.appointment_no, mr.doctor_id, d.staff_name AS doctor_name, mr.assistant_id, s.staff_name AS assistant_name, mr.visit_type, mr.visit_date, mr.chief_complaint, mr.present_illness, mr.oral_examination, mr.auxiliary_examination, mr.preliminary_diagnosis, mr.treatment_advice, mr.doctor_advice, mr.revisit_advice, mr.next_visit_date, mr.record_status, mr.signed_flag, mr.signed_at, mr.print_count, mr.remark FROM medical_record mr LEFT JOIN clinic c ON c.id = mr.clinic_id LEFT JOIN patient p ON p.id = mr.patient_id LEFT JOIN appointment a ON a.id = mr.appointment_id LEFT JOIN staff d ON d.id = mr.doctor_id LEFT JOIN staff s ON s.id = mr.assistant_id WHERE mr.id = #{id} AND mr.org_id = #{orgId} AND mr.is_deleted = 0
AND mr.clinic_id IN
#{clinicId}
AND mr.doctor_id = #{staffId}
LIMIT 1
